    /// <summary>
    /// fetches prediction-market events matching the given scope (query/queries/tags/eventId/slug — required) and caches their markets and outcomes on the instance; for an unscoped top-volume browse use fetchMarkets ()
    /// </summary>
    /// <remarks>
    /// See <see href="https://docs.polymarket.com/api-reference/search/search-markets-events-and-profiles"/>  <br/>
    /// See <see href="https://docs.polymarket.com/api-reference/events/list-events"/>  <br/>
    /// <list type="table">
    /// <item>
    /// <term>params</term>
    /// <description>
    /// object : extra exchange-specific parameters
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.query</term>
    /// <description>
    /// string : a single keyword search term
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.limit</term>
    /// <description>
    /// int : max number of events to return
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.sort</term>
    /// <description>
    /// string : 'volume' (default), 'liquidity' or 'newest' — mapped to the gamma order field
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.status</term>
    /// <description>
    /// string : 'active' (default), 'inactive', 'closed' or 'all' ('inactive' and 'closed' are interchangeable)
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.searchIn</term>
    /// <description>
    /// string : when searching, restrict the match to 'title' (default), 'description' or 'both'
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.eventId</term>
    /// <description>
    /// string : direct lookup by event id (short-circuits the listing/search)
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.slug</term>
    /// <description>
    /// string : direct lookup by event slug
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.searchPageSize</term>
    /// <description>
    /// int : search page size (gamma limit_per_type, default 100); lower it to shrink the download when a small limit is enough, higher to over-fetch before client-side status/title filtering
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.maxSearchPages</term>
    /// <description>
    /// int : max search pages to fetch when no limit is given (default 5), bounding a broad query
    /// </description>
    /// </item>
    /// </list>
    /// </remarks>
    /// <returns> <term>object[]</term> an array of event structures.</returns>
    public async Task<List<PredictionEvent>> FetchEvents(Dictionary<string, object> parameters)
    {
        var res = await this.fetchEvents(parameters);
        return ((IList<object>)res).Select(item => new PredictionEvent(item)).ToList<PredictionEvent>();
    }
